/**
 * A generic suggestion group used by both key and value suggestion pipelines.
 * @internal
 */
export type SuggestionGroup<T> = {
  id: string;
  label?: string;
  'aria-label'?: string;
  suggestions: T[];
};

/**
 * Resolves the effective ID for a suggestion group config.
 * Falls back through id → label → aria-label → provided fallback.
 * @internal
 */
export function resolveGroupId(
  config: { id?: string; label?: string; 'aria-label'?: string },
  fallback: string,
): string {
  return config.id ?? config.label ?? config['aria-label'] ?? fallback;
}
